// Implement a 3-to-8 decoder. When enable is high, decode the 3-bit input to assert one of 8 output lines.
module decoder_3to8(
    input wire en,
    input wire [2:0] in,
    output reg [7:0] out
);
always @* begin
    out = 8'b00000000;
    if (en) begin
        case (in)
            3'b000: out[0] = 1'b1;
            3'b001: out[1] = 1'b1;
            3'b010: out[2] = 1'b1;
            3'b011: out[3] = 1'b1;
            3'b100: out[4] = 1'b1;
            3'b101: out[5] = 1'b1;
            3'b110: out[6] = 1'b1;
            3'b111: out[7] = 1'b1;
        endcase
    end
end
endmodule

// Implement a 4-bit priority encoder that outputs the index of the highest priority active input.
module priority_encoder(
    input wire [3:0] in,
    output reg [1:0] pos,
    output reg valid
);
module priority_encoder(
    input wire [3:0] in,
    output reg [1:0] pos,
    output reg valid
);
    always @(*) begin
        pos = 2'b00;
        valid = 1'b0;
        if (in[3]) begin
            pos = 2'b11;
            valid = 1'b1;
        end else if (in[2]) begin
            pos = 2'b10;
            valid = 1'b1;
        end else if (in[1]) begin
            pos = 2'b01;
            valid = 1'b1;
        end else if (in[0]) begin
            pos = 2'b00;
            valid = 1'b1;
        end
    end
endmodule

// Implement a traffic light FSM with states: GREEN, YELLOW, RED. Transition GREEN->YELLOW->RED->GREEN on each tick signal.
module traffic_light(
    input wire clk,
    input wire rst,
    input wire tick,
    output reg [1:0] state
);
    localparam GREEN=2'd0, YELLOW=2'd1, RED=2'd2;
always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= GREEN;
    end else if (tick) begin
        case (state)
            GREEN: state <= YELLOW;
            YELLOW: state <= RED;
            RED: state <= GREEN;
            default: state <= GREEN;
        endcase
    end
end
endmodule

// Implement a Moore FSM that detects the sequence 1011 on a serial input. Assert 'detected' when the full sequence is seen.
module seq_detector(
    input wire clk,
    input wire rst,
    input wire din,
    output reg detected
);
module seq_detector(
    input wire clk,
    input wire rst,
    input wire din,
    output reg detected
);

    // Define the states
    typedef enum reg [2:0] {
        S0,  // Initial state
        S1,  // Detected '1'
        S2,  // Detected '10'
        S3,  // Detected '101'
        S4   // Detected '1011' (detected is asserted)
    } state_t;

    // State and next state registers
    state_t state, next_state;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S0;
        end else begin
            state <= next_state;
        end
    end

    // Next state and output logic
    always @* begin
        next_state = state;
        detected = 1'b0;

        case (state)
            S0: begin
                if (din) begin
                    next_state = S1;
                end else begin
                    next_state = S0;
                end
            end

            S1: begin
                if (din) begin
                    next_state = S1;
                end else begin
                    next_state = S2;
                end
            end

            S2: begin
                if (din) begin
                    next_state = S3;
                end else begin
                    next_state = S0;
                end
            end

            S3: begin
                if (din) begin
                    next_state = S4;
                end else begin
                    next_state = S0;
                end
            end

            S4: begin
                if (din) begin
                    next_state = S1;
                end else begin
                    next_state = S0;
                end
                detected = 1'b1;
            end

            default: next_state = S0;
        endcase
    end

endmodule

// Implement a vending machine FSM. Accept nickels (5 cents) and dimes (10 cents). Dispense when total >= 15 cents and give change.
module vending(
    input wire clk,
    input wire rst,
    input wire nickel,
    input wire dime,
    output reg dispense,
    output reg [3:0] change
);
module vending(
    input wire clk,
    input wire rst,
    input wire nickel,
    input wire dime,
    output reg dispense,
    output reg [3:0] change
);

    // State definition
    typedef enum reg [2:0] {
        S0,    // 0 cents
        S5,    // 5 cents
        S10,   // 10 cents
        S15,   // 15 cents
        S20,   // 20 cents
        S25,   // 25 cents
        S30    // 30 cents
    } state_t;

    state_t state, next_state;

    // State transition logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S0;
        end else begin
            state <= next_state;
        end
    end

    // Next state logic
    always @(*) begin
        next_state = state;
        dispense = 1'b0;
        change = 4'b0000;

        case (state)
            S0: begin
                if (nickel) next_state = S5;
                if (dime) next_state = S10;
            end
            S5: begin
                if (nickel) next_state = S10;
                if (dime) next_state = S15;
            end
            S10: begin
                if (nickel) next_state = S15;
                if (dime) next_state = S20;
            end
            S15: begin
                dispense = 1'b1;
                change = 4'b0000;
                next_state = S0;
            end
            S20: begin
                dispense = 1'b1;
                change = 4'b0010; // 10 cents change
                next_state = S0;
            end
            S25: begin
                dispense = 1'b1;
                change = 4'b0100; // 20 cents change
                next_state = S0;
            end
            S30: begin
                dispense = 1'b1;
                change = 4'b0110; // 25 cents change
