// Implement an 8-bit up counter with asynchronous active-low reset and synchronous enable.
module counter(
    input wire clk,
    input wire rst_n,
    input wire en,
    output reg [7:0] count
);
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 8'b0;
    end else if (en) begin
        count <= count + 1;
    end
end
endmodule

// Implement an 8-bit shift register with asynchronous reset, serial input, and parallel output.
module shift_reg(
    input wire clk,
    input wire rst_n,
    input wire si,
    output reg [7:0] po
);
module shift_reg(
    input wire clk,
    input wire rst_n,
    input wire si,
    output reg [7:0] po
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        po <= 8'b00000000;
    end else begin
        po <= {po[6:0], si};
    end
end

endmodule

// Implement a FIFO controller with read/write pointers, full/empty flags. Depth is 8.
module fifo_ctrl(
    input wire clk,
    input wire rst,
    input wire wr,
    input wire rd,
    output reg full,
    output reg empty,
    output reg [2:0] wr_ptr,
    output reg [2:0] rd_ptr
);
module fifo_ctrl(
    input wire clk,
    input wire rst,
    input wire wr,
    input wire rd,
    output reg full,
    output reg empty,
    output reg [2:0] wr_ptr,
    output reg [2:0] rd_ptr
);

    // FIFO depth is 8, so pointers are 3 bits wide
    reg [2:0] next_wr_ptr, next_rd_ptr;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            wr_ptr <= 3'b000;
            rd_ptr <= 3'b000;
            full <= 1'b0;
            empty <= 1'b1;
        end else begin
            if (wr) begin
                next_wr_ptr <= wr_ptr + 1'b1;
                if (wr_ptr == rd_ptr) begin
                    full <= 1'b1;
                end
            end
            if (rd) begin
                next_rd_ptr <= rd_ptr + 1'b1;
                if (rd_ptr == wr_ptr) begin
                    empty <= 1'b1;
                end
            end
            wr_ptr <= next_wr_ptr;
            rd_ptr <= next_rd_ptr;
        end
    end

endmodule

// Implement a 4-to-1 multiplexer with 8-bit data paths.
module mux4(
    input wire [7:0] d0, d1, d2, d3,
    input wire [1:0] sel,
    output reg [7:0] out
);
always @* begin
    case (sel)
        2'b00: out = d0;
        2'b01: out = d1;
        2'b10: out = d2;
        2'b11: out = d3;
        default: out = d0;
    endcase
end
endmodule
